Reference output:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = "~> 3.6"
    }
  }
}

provider "aws" {
  region = "us-east-1"
}

resource "random_id" "suffix" {
  byte_length = 4
}

resource "aws_s3_bucket" "trace_demo" {
  bucket        = "trace-demo-${random_id.suffix.hex}"
  force_destroy = true

  tags = {
    Purpose = "trace-demo"
  }
}

resource "aws_s3_bucket_public_access_block" "trace_demo" {
  bucket = aws_s3_bucket.trace_demo.id

  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_versioning" "trace_demo" {
  bucket = aws_s3_bucket.trace_demo.id

  versioning_configuration {
    status = "Enabled"
  }
}

resource "aws_s3_bucket_server_side_encryption_configuration" "trace_demo" {
  bucket = aws_s3_bucket.trace_demo.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
}
